class StockPrice {
public:
    vector<pair<int, int>> prices;

    StockPrice() {}

    void update(int timestamp, int price) {
        prices.push_back({timestamp, price});
    }

    int current() {
        if (prices.empty()) return -1;
        return prices.back().second;
    }

    int maximum() {
        int max_price = prices[0].second;
        for (int i = 1; i < prices.size(); i++) {
            if (prices[i].second > max_price)
                max_price = prices[i].second;
        }
        return max_price;
    }

    int minimum() {
        int min_price = prices[0].second;
        for (int i = 1; i < prices.size(); i++) {
            if (prices[i].second < min_price)
                min_price = prices[i].second;
        }
        return min_price;
    }
};
```

